import React from 'react';
import { termsContent } from 'data/terms';
import ''

const TermsOfUsePage = () => {
  return (
    <>
      <main>
        <div className="container">
          <div className="text-content-page">
            {/* Renderiza o título e a data a partir dos dados */}
            <h1>{termsContent.title}</h1>
            <p className="last-updated">{termsContent.lastUpdated}</p>

            {/* 2. Faz um loop nas seções e renderiza cada uma */}
            {termsContent.sections.map((section, index) => (
              // O React.Fragment (<>) é usado para agrupar os elementos sem criar um div extra
              <React.Fragment key={index}>
                <h2>{section.title}</h2>
                {section.content}
              </React.Fragment>
            ))}

          </div>
        </div>
      </main>
    </>
  );
};

export default TermsOfUsePage;
